 42→#[tauri::command]
 43→fn get_transcript(
 44→    repo_path: String,
 45→    checkpoint_id: String,
 46→    session_index: u32,
 47→) -> Result<Vec<session::TranscriptMessage>, String> {
 48→    let repo = git::open_repo(&repo_path)?;
 49→
 50→    let prefix = &checkpoint_id[..2];
 51→    let suffix = &checkpoint_id[2..];
 52→    let session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
 53→
 54→    // Read the checkpoint metadata to find the actual transcript path
 55→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
 56→    let transcript_path = read_blob(&repo, &meta_path)
 57→        .ok()
 58→        .and_then(|meta_content| {
 59→            let meta: serde_json::Value = serde_json::from_str(&meta_content).ok()?;
 60→            let sessions = meta.get("sessions")?.as_array()?;
 61→            let session = sessions.get(session_index as usize)?;
 62→            session.get("transcript")?.as_str().map(|s| s.to_string())
 63→        });
 64→
 65→    // Build candidates: metadata path (may be absolute from tree root), then fallbacks
 66→    let mut candidates = Vec::new();
 67→    if let Some(ref path) = transcript_path {
 68→        // Paths from metadata may be absolute (leading /) — strip it for tree lookup
 69→        candidates.push(path.trim_start_matches('/').to_string());
 70→    }
 71→    candidates.push(format!("{}/full.jsonl", session_dir));
 72→    candidates.push(format!("{}/transcript.jsonl", session_dir));
 73→
 74→    for path in &candidates {
 75→        if let Ok(content) = read_blob(&repo, path) {
 76→            return Ok(session::read_transcript(&content));
 77→        }
 78→    }
 79→
 80→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
 81→}
