128→#[tauri::command]
129→fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
130→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
131→    if !log_path.exists() {
132→        return Err("No log file found".to_string());
133→    }
134→
135→    let metadata = std::fs::metadata(&log_path)
136→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
137→    let file_size_bytes = metadata.len();
138→
139→    let file = std::fs::File::open(&log_path)
140→        .map_err(|e| format!("Failed to open log file: {}", e))?;
141→
142→    // Count total lines
143→    let reader = BufReader::new(&file);
144→    let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();
145→    let total_lines = all_lines.len() as u32;
146→
147→    // Take last N lines
148→    let start = all_lines.len().saturating_sub(tail_lines as usize);
149→    let lines = all_lines[start..].to_vec();
150→
151→    Ok(EntireLogResult {
152→        lines,
153→        total_lines,
154→        file_size_bytes,
155→    })
156→}
157→
158→#[tauri::command]
159→fn get_checkpoint_logs(
160→    repo_path: String,
161→    checkpoint_id: String,
162→    session_ids: Vec<String>,
163→) -> Result<EntireLogResult, String> {
164→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
165→    if !log_path.exists() {
166→        return Ok(EntireLogResult {
167→            lines: Vec::new(),
168→            total_lines: 0,
169→            file_size_bytes: 0,
170→        });
171→    }
172→
173→    let metadata = std::fs::metadata(&log_path)
174→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
175→    let file_size_bytes = metadata.len();
176→
177→    let file = std::fs::File::open(&log_path)
178→        .map_err(|e| format!("Failed to open log file: {}", e))?;
179→
180→    let reader = BufReader::new(file);
181→    let mut matching_lines = Vec::new();
182→
183→    for line in reader.lines() {
184→        let line = match line {
185→            Ok(l) => l,
186→            Err(_) => continue,
187→        };
188→
189→        // Parse each line as JSON and check for matching session_id or checkpoint_id
190→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(&line) {
191→            let line_session_id = value.get("session_id").and_then(|v| v.as_str());
192→            let line_checkpoint_id = value.get("checkpoint_id").and_then(|v| v.as_str());
193→
194→            let matches = line_session_id
195→                .map(|sid| session_ids.iter().any(|s| s == sid))
196→                .unwrap_or(false)
197→                || line_checkpoint_id
198→                    .map(|cid| cid == checkpoint_id)
199→                    .unwrap_or(false);
200→
201→            if matches {
202→                matching_lines.push(line);
203→            }
204→        }
205→    }
206→
207→    Ok(EntireLogResult {
208→        total_lines: matching_lines.len() as u32,
209→        lines: matching_lines,
210→        file_size_bytes,
211→    })
212→}
