import { useState, useEffect } from "react";
import {
  GitBranch,
  BookOpen,
  Plus,
  ChevronRight,
  ChevronDown,
  FolderGit2,
  Loader2,
  PanelLeftClose,
  PanelLeftOpen,
} from "lucide-react";
import type { Tab } from "../../App";
import type { BranchInfo, WorktreeInfo } from "../../lib/ipc";
import { useReposQuery } from "../../hooks/use-tauri-query";

interface SidebarProps {
  activeTab: Tab;
  onBranchSelect: (branch: BranchInfo, repoPath: string) => void;
  onWorktreeSelect: (wt: WorktreeInfo, repoPath: string) => void;
  onNewSession?: () => void;
}

export function Sidebar({
  activeTab,
  onBranchSelect,
  onWorktreeSelect,
  onNewSession,
}: SidebarProps) {
  const { data: realRepos, isLoading, error } = useReposQuery();

  const repos = realRepos ?? [];

  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set());
  const [repoListCollapsed, setRepoListCollapsed] = useState(false);
  const [collapsed, setCollapsed] = useState(false);

  // Auto-expand all repos when data loads
  useEffect(() => {
    setExpandedRepos(new Set(repos.map((r) => r.path)));
  }, [repos]);

  function toggleRepo(path: string) {
    setExpandedRepos((prev) => {
      const next = new Set(prev);
      if (next.has(path)) next.delete(path);
      else next.add(path);
      return next;
    });
  }

  const worktreeBranches = new Set(
    repos.flatMap((r) => r.worktrees.map((wt) => wt.branch))
  );

  // Collapsed state: narrow icon rail
  if (collapsed) {
    return (
      <div className="flex w-[48px] shrink-0 flex-col items-center border-r border-border bg-bg-raised py-3">
        <button
          onClick={() => setCollapsed(false)}
          className="mb-4 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
          title="Expand sidebar"
        >
          <PanelLeftOpen size={16} />
        </button>
        {repos.map((repo) => (
          <button
            key={repo.path}
            className="mb-1 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title={repo.name}
          >
            <BookOpen size={14} />
          </button>
        ))}
        <div className="mt-auto">
          <button
            onClick={onNewSession}
            className="flex h-8 w-8 items-center justify-center rounded text-accent-fg transition-colors hover:bg-accent-bg"
            title="New Session"
          >
            <Plus size={16} />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex w-[240px] shrink-0 flex-col border-r border-border bg-bg-raised">
      {/* Header */}
      <div className="flex items-center border-b border-border-subtle p-4">
        <h2 className="flex flex-1 items-center gap-2 text-[15px] font-semibold text-fg">
          <FolderGit2 size={18} />
          Repositories
        </h2>
        <button
          onClick={() => setCollapsed(true)}
          className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
          title="Collapse sidebar"
        >
          <PanelLeftClose size={14} />
        </button>
      </div>

      {/* Repo list */}
      <div className="flex-1 overflow-y-auto py-3">
        <button
          onClick={() => setRepoListCollapsed(!repoListCollapsed)}
          className="mb-1 flex w-full items-center gap-2 px-4 text-left"
        >
          {repoListCollapsed ? (
            <ChevronRight size={10} className="text-fg-subtle" />
          ) : (
            <ChevronDown size={10} className="text-fg-subtle" />
          )}
          <span className="text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
            Active
          </span>
          {isLoading && <Loader2 size={10} className="animate-spin text-fg-subtle" />}
        </button>

        {error && !repoListCollapsed && (
          <div className="px-4 py-2 text-[11px] text-red">
            Failed to load repos
          </div>
        )}

        {!repoListCollapsed && repos.map((repo) => (
          <div key={repo.path}>
            <button
              onClick={() => toggleRepo(repo.path)}
              className="flex w-full items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
            >
              {expandedRepos.has(repo.path) ? (
                <ChevronDown size={14} />
              ) : (
                <ChevronRight size={14} />
              )}
              <BookOpen size={14} />
              {repo.name}
              <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
                {repo.branches.length}
              </span>
            </button>

            {expandedRepos.has(repo.path) && (
              <div className="pl-8">
                {repo.branches.map((branch) => {
                  const isWorktree = worktreeBranches.has(branch.name);
                  const isActive =
                    activeTab.branch === branch.name &&
                    activeTab.repoPath === repo.path;

                  return (
                    <button
                      key={branch.name}
                      onClick={() => {
                        const wt = repo.worktrees.find(
                          (w) => w.branch === branch.name
                        );
                        if (wt) {
                          onWorktreeSelect(wt, repo.path);
                        } else {
                          onBranchSelect(branch, repo.path);
                        }
                      }}
                      className={`flex w-full items-center gap-2 px-2 py-[7px] text-[13px] transition-colors ${
                        isActive
                          ? "bg-accent-bg text-accent-fg"
                          : "text-fg-muted hover:bg-bg-hover hover:text-fg"
                      }`}
                    >
                      <GitBranch size={12} />
                      {branch.name}
                      {isWorktree && (
                        <span className="ml-auto rounded bg-green-bg px-1.5 py-0.5 text-[9px] font-medium text-green">
                          worktree
                        </span>
                      )}
                      {!isWorktree && (
                        <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
                          {branch.checkpoint_count}
                        </span>
                      )}
                    </button>
                  );
                })}
              </div>
            )}
          </div>
        ))}

        {!repoListCollapsed && repos.length === 0 && !isLoading && !error && (
          <div className="px-4 py-6 text-center text-[11px] text-fg-subtle">
            No repositories discovered
          </div>
        )}
      </div>

      {/* New session button */}
      <div className="border-t border-border-subtle p-3">
        <button
          onClick={onNewSession}
          className="flex w-full items-center justify-center gap-1.5 rounded-lg bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover"
        >
          <Plus size={14} />
          New Session
        </button>
      </div>
